import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import eventService from '../services/eventService';
import '../components/CreateEvent.css'; // Assuming a CSS file for styling

const CreateEvent = () => {
    const [formData, setFormData] = useState({
        eventName: '',
        eventDescription: '',
        eventType: 'normal',
        eligibility: '',
        registrationDeadline: '',
        eventStartDate: '',
        eventEndDate: '',
        registrationLimit: '',
        registrationFee: '',
        eventTags: '',
    });
    const [error, setError] = useState(null);
    const [loading, setLoading] = useState(false);
    const navigate = useNavigate();

    const {
        eventName,
        eventDescription,
        eventType,
        eligibility,
        registrationDeadline,
        eventStartDate,
        eventEndDate,
        registrationLimit,
        registrationFee,
        eventTags,
    } = formData;

    const onChange = (e) => {
        setFormData({ ...formData, [e.target.name]: e.target.value });
    };

    const onSubmit = async (e) => {
        e.preventDefault();
        setLoading(true);
        setError(null);

        try {
            const user = JSON.parse(localStorage.getItem('user'));
            const token = user ? user.token : null;

            if (!token) {
                setError('You need to be logged in to create an event.');
                setLoading(false);
                return;
            }

            const eventData = {
                ...formData,
                registrationLimit: registrationLimit ? Number(registrationLimit) : undefined,
                registrationFee: registrationFee ? Number(registrationFee) : undefined,
                eventTags: eventTags.split(',').map(tag => tag.trim()).filter(tag => tag !== ''),
            };

            await eventService.createEvent(eventData, token);
            navigate('/events'); // Redirect to event dashboard
        } catch (err) {
            setError(err.response?.data?.message || 'Failed to create event.');
            console.error(err);
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="create-event-container">
            <h1>Create New Event</h1>
            <form onSubmit={onSubmit} className="create-event-form">
                {error && <p className="error-message">{error}</p>}
                <div className="form-group">
                    <label htmlFor="eventName">Event Name</label>
                    <input
                        type="text"
                        id="eventName"
                        name="eventName"
                        value={eventName}
                        onChange={onChange}
                        required
                    />
                </div>
                <div className="form-group">
                    <label htmlFor="eventDescription">Event Description</label>
                    <textarea
                        id="eventDescription"
                        name="eventDescription"
                        value={eventDescription}
                        onChange={onChange}
                        required
                    ></textarea>
                </div>
                <div className="form-group">
                    <label htmlFor="eventType">Event Type</label>
                    <select id="eventType" name="eventType" value={eventType} onChange={onChange}>
                        <option value="normal">Normal</option>
                        <option value="merch">Merch</option>
                    </select>
                </div>
                <div className="form-group">
                    <label htmlFor="eligibility">Eligibility</label>
                    <input
                        type="text"
                        id="eligibility"
                        name="eligibility"
                        value={eligibility}
                        onChange={onChange}
                    />
                </div>
                <div className="form-group">
                    <label htmlFor="registrationDeadline">Registration Deadline</label>
                    <input
                        type="date"
                        id="registrationDeadline"
                        name="registrationDeadline"
                        value={registrationDeadline}
                        onChange={onChange}
                        required
                    />
                </div>
                <div className="form-group">
                    <label htmlFor="eventStartDate">Event Start Date</label>
                    <input
                        type="date"
                        id="eventStartDate"
                        name="eventStartDate"
                        value={eventStartDate}
                        onChange={onChange}
                        required
                    />
                </div>
                <div className="form-group">
                    <label htmlFor="eventEndDate">Event End Date</label>
                    <input
                        type="date"
                        id="eventEndDate"
                        name="eventEndDate"
                        value={eventEndDate}
                        onChange={onChange}
                        required
                    />
                </div>
                <div className="form-group">
                    <label htmlFor="registrationLimit">Registration Limit</label>
                    <input
                        type="number"
                        id="registrationLimit"
                        name="registrationLimit"
                        value={registrationLimit}
                        onChange={onChange}
                    />
                </div>
                <div className="form-group">
                    <label htmlFor="registrationFee">Registration Fee</label>
                    <input
                        type="number"
                        id="registrationFee"
                        name="registrationFee"
                        value={registrationFee}
                        onChange={onChange}
                    />
                </div>
                <div className="form-group">
                    <label htmlFor="eventTags">Event Tags (comma-separated)</label>
                    <input
                        type="text"
                        id="eventTags"
                        name="eventTags"
                        value={eventTags}
                        onChange={onChange}
                    />
                </div>
                <button type="submit" disabled={loading}>
                    {loading ? 'Creating...' : 'Create Event'}
                </button>
            </form>
        </div>
    );
};

export default CreateEvent;

import React, { useState } from 'react';
import '../components/FormBuilder.css'; // Assuming a CSS file for styling

const FormBuilder = ({ onFormChange, initialFormFields = [] }) => {
    const [formFields, setFormFields] = useState(initialFormFields);
    const [newFieldType, setNewFieldType] = useState('text');
    const [newFieldLabel, setNewFieldLabel] = useState('');

    const addField = () => {
        if (!newFieldLabel.trim()) return;

        const newField = {
            id: Date.now(), // Unique ID for the field
            label: newFieldLabel,
            type: newFieldType,
            required: false,
            options: newFieldType === 'dropdown' ? ['Option 1', 'Option 2'] : [], // Default options for dropdown
        };
        const updatedFormFields = [...formFields, newField];
        setFormFields(updatedFormFields);
        onFormChange(updatedFormFields);
        setNewFieldLabel('');
    };

    const removeField = (id) => {
        const updatedFormFields = formFields.filter((field) => field.id !== id);
        setFormFields(updatedFormFields);
        onFormChange(updatedFormFields);
    };

    const toggleRequired = (id) => {
        const updatedFormFields = formFields.map((field) =>
            field.id === id ? { ...field, required: !field.required } : field
        );
        setFormFields(updatedFormFields);
        onFormChange(updatedFormFields);
    };

    const moveField = (id, direction) => {
        const index = formFields.findIndex((field) => field.id === id);
        if (index === -1) return;

        const newIndex = direction === 'up' ? index - 1 : index + 1;
        if (newIndex < 0 || newIndex >= formFields.length) return;

        const updatedFormFields = [...formFields];
        const [movedField] = updatedFormFields.splice(index, 1);
        updatedFormFields.splice(newIndex, 0, movedField);
        setFormFields(updatedFormFields);
        onFormChange(updatedFormFields);
    };

    const handleOptionChange = (fieldId, optionIndex, newValue) => {
        const updatedFormFields = formFields.map(field => {
            if (field.id === fieldId && field.type === 'dropdown') {
                const newOptions = [...field.options];
                newOptions[optionIndex] = newValue;
                return { ...field, options: newOptions };
            }
            return field;
        });
        setFormFields(updatedFormFields);
        onFormChange(updatedFormFields);
    };

    const addOption = (fieldId) => {
        const updatedFormFields = formFields.map(field => {
            if (field.id === fieldId && field.type === 'dropdown') {
                return { ...field, options: [...field.options, `Option ${field.options.length + 1}`] };
            }
            return field;
        });
        setFormFields(updatedFormFields);
        onFormChange(updatedFormFields);
    };

    const removeOption = (fieldId, optionIndex) => {
        const updatedFormFields = formFields.map(field => {
            if (field.id === fieldId && field.type === 'dropdown') {
                const newOptions = field.options.filter((_, idx) => idx !== optionIndex);
                return { ...field, options: newOptions };
            }
            return field;
        });
        setFormFields(updatedFormFields);
        onFormChange(updatedFormFields);
    };


    return (
        <div className="form-builder-container">
            <h3>Custom Registration Form Builder</h3>
            <div className="add-field-section">
                <input
                    type="text"
                    placeholder="Field Label"
                    value={newFieldLabel}
                    onChange={(e) => setNewFieldLabel(e.target.value)}
                />
                <select value={newFieldType} onChange={(e) => setNewFieldType(e.target.value)}>
                    <option value="text">Text Input</option>
                    <option value="email">Email Input</option>
                    <option value="number">Number Input</option>
                    <option value="textarea">Text Area</option>
                    <option value="checkbox">Checkbox</option>
                    <option value="dropdown">Dropdown</option>
                    <option value="file">File Upload</option>
                </select>
                <button onClick={addField}>Add Field</button>
            </div>

            <div className="form-fields-list">
                {formFields.length === 0 ? (
                    <p>No custom fields added yet.</p>
                ) : (
                    formFields.map((field, index) => (
                        <div key={field.id} className="form-field-item">
                            <span>{field.label} ({field.type}) {field.required && '*'}</span>
                            <div className="field-controls">
                                <button onClick={() => toggleRequired(field.id)}>
                                    {field.required ? 'Make Flexible' : 'Make Required'}
                                </button>
                                <button onClick={() => moveField(field.id, 'up')} disabled={index === 0}>
                                    Up
                                </button>
                                <button onClick={() => moveField(field.id, 'down')} disabled={index === formFields.length - 1}>
                                    Down
                                </button>
                                <button onClick={() => removeField(field.id)}>Remove</button>
                            </div>
                            {field.type === 'dropdown' && (
                                <div className="dropdown-options">
                                    <h4>Options:</h4>
                                    {field.options.map((option, optIndex) => (
                                        <div key={optIndex} className="dropdown-option-item">
                                            <input
                                                type="text"
                                                value={option}
                                                onChange={(e) => handleOptionChange(field.id, optIndex, e.target.value)}
                                            />
                                            <button onClick={() => removeOption(field.id, optIndex)}>Remove Option</button>
                                        </div>
                                    ))}
                                    <button onClick={() => addOption(field.id)}>Add Option</button>
                                </div>
                            )}
                        </div>
                    ))
                )}
            </div>
        </div>
    );
};

export default FormBuilder;

