const mongoose = require('mongoose');

const eventSchema = new mongoose.Schema({
    eventName: {
        type: String,
        required: true,
    },
    eventDescription: {
        type: String,
        required: true,
    },
    eventType: {
        type: String,
        enum: ['normal', 'merch'],
        default: 'normal',
    },
    eligibility: {
        type: String,
    },
    registrationDeadline: {
        type: Date,
        required: true,
    },
    eventStartDate: {
        type: Date,
        required: true,
    },
    eventEndDate: {
        type: Date,
        required: true,
    },
    registrationLimit: {
        type: Number,
    },
    registrationFee: {
        type: Number,
        default: 0,
    },
    organizerId: {
        type: mongoose.Schema.Types.ObjectId,
        ref: 'User',
        required: true,
    },
    eventTags: {
        type: [String],
    },
    status: {
        type: String,
        enum: ['draft', 'published', 'ongoing', 'completed', 'closed'],
        default: 'draft',
    },
    registrationForm: {
        type: Array, // Stores the structure of the custom registration form
        default: [],
    },
}, {
    timestamps: true,
});

module.exports = mongoose.model('Event', eventSchema);

const asyncHandler = require('express-async-handler');
const Event = require('../models/Event');
const User = require('../models/User'); // Assuming User model is needed for organizer role check

// @desc    Create new event
// @route   POST /api/events
// @access  Private/Organizer
const createEvent = asyncHandler(async (req, res) => {
    const {
        eventName,
        eventDescription,
        eventType,
        eligibility,
        registrationDeadline,
        eventStartDate,
        eventEndDate,
        registrationLimit,
        registrationFee,
        eventTags,
        registrationForm
    } = req.body;

    // Check if user is an organizer
    if (req.user.role !== 'organizer') {
        res.status(403);
        throw new Error('Not authorized to create an event. Only organizers can create events.');
    }

    const event = new Event({
        eventName,
        eventDescription,
        eventType,
        eligibility,
        registrationDeadline,
        eventStartDate,
        eventEndDate,
        registrationLimit,
        registrationFee,
        organizerId: req.user._id, // Organizer ID from authenticated user
        eventTags,
        registrationForm,
        status: 'draft', // Default status
    });

    const createdEvent = await event.save();
    res.status(201).json(createdEvent);
});

// @desc    Get all events
// @route   GET /api/events
// @access  Public
const getEvents = asyncHandler(async (req, res) => {
    const events = await Event.find({}).populate('organizerId', 'username email');
    res.json(events);
});

// @desc    Get single event by ID
// @route   GET /api/events/:id
// @access  Public
const getEventById = asyncHandler(async (req, res) => {
    const event = await Event.findById(req.params.id).populate('organizerId', 'username email');

    if (event) {
        res.json(event);
    } else {
        res.status(404);
        throw new Error('Event not found');
    }
});

// @desc    Update event
// @route   PUT /api/events/:id
// @access  Private/Organizer
const updateEvent = asyncHandler(async (req, res) => {
    const {
        eventName,
        eventDescription,
