import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import eventService from '../services/eventService';
import FormBuilder from './FormBuilder'; // Import FormBuilder
import '../components/CreateEvent.css'; // Assuming a CSS file for styling

const CreateEvent = () => {
    const [formData, setFormData] = useState({
        eventName: '',
        eventDescription: '',
        eventType: 'normal',
        eligibility: '',
        registrationDeadline: '',
        eventStartDate: '',
        eventEndDate: '',
        registrationLimit: '',
        registrationFee: '',
        eventTags: '',
    });
    const [customFormFields, setCustomFormFields] = useState([]); // New state for custom form fields
    const [error, setError] = useState(null);
    const [loading, setLoading] = useState(false);
    const navigate = useNavigate();

    const {
        eventName,
        eventDescription,
        eventType,
        eligibility,
        registrationDeadline,
        eventStartDate,
        eventEndDate,
        registrationLimit,
        registrationFee,
        eventTags,
    } = formData;

    const onChange = (e) => {
        setFormData({ ...formData, [e.target.name]: e.target.value });
    };

    // Callback function to receive form fields from FormBuilder
    const handleCustomFormChange = (fields) => {
        setCustomFormFields(fields);
    };

    const onSubmit = async (e) => {
        e.preventDefault();
        setLoading(true);
        setError(null);

        try {
            const user = JSON.parse(localStorage.getItem('user'));
            const token = user ? user.token : null;

            if (!token) {
                setError('You need to be logged in to create an event.');
                setLoading(false);
                return;
            }

            const eventData = {
                ...formData,
                registrationLimit: registrationLimit ? Number(registrationLimit) : undefined,
                registrationFee: registrationFee ? Number(registrationFee) : undefined,
                eventTags: eventTags.split(',').map(tag => tag.trim()).filter(tag => tag !== ''),
                customFormFields: customFormFields, // Include custom form fields
            };

            await eventService.createEvent(eventData, token);
            navigate('/events'); // Redirect to event dashboard
        } catch (err) {
            setError(err.response?.data?.message || 'Failed to create event.');
            console.error(err);
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="create-event-container">
            <h1>Create New Event</h1>
            <form onSubmit={onSubmit} className="create-event-form">
                {error && <p className="error-message">{error}</p>}
                <div className="form-group">
                    <label htmlFor="eventName">Event Name</label>
                    <input
                        type="text"
                        id="eventName"
                        name="eventName"
                        value={eventName}
                        onChange={onChange}
                        required
                    />
                </div>
                <div className="form-group">
                    <label htmlFor="eventDescription">Event Description</label>
                    <textarea
                        id="eventDescription"
                        name="eventDescription"
                        value={eventDescription}
                        onChange={onChange}
                        required
                    ></textarea>
                </div>
                <div className="form-group">
                    <label htmlFor="eventType">Event Type</label>
                    <select id="eventType" name="eventType" value={eventType} onChange={onChange}>
                        <option value="normal">Normal</option>
                        <option value="merch">Merch</option>
                    </select>
                </div>
                <div className="form-group">
                    <label htmlFor="eligibility">Eligibility</label>
                    <input
                        type="text"
                        id="eligibility"
                        name="eligibility"
                        value={eligibility}
                        onChange={onChange}
                    />
                </div>
                <div className="form-group">
                    <label htmlFor="registrationDeadline">Registration Deadline</label>
                    <input
                        type="date"
                        id="registrationDeadline"
                        name="registrationDeadline"
                        value={registrationDeadline}
                        onChange={onChange}
                        required
                    />
                </div>
                <div className="form-group">
                    <label htmlFor="eventStartDate">Event Start Date</label>
                    <input
                        type="date"
                        id="eventStartDate"
                        name="eventStartDate"
                        value={eventStartDate}
                        onChange={onChange}
                        required
                    />
                </div>
                <div className="form-group">
                    <label htmlFor="eventEndDate">Event End Date</label>
                    <input
                        type="date"
                        id="eventEndDate"
                        name="eventEndDate"
                        value={eventEndDate}
                        onChange={onChange}
                        required
                    />
                </div>
                <div className="form-group">
                    <label htmlFor="registrationLimit">Registration Limit</label>
                    <input
                        type="number"
                        id="registrationLimit"
                        name="registrationLimit"
                        value={registrationLimit}
                        onChange={onChange}
                    />
                </div>
                <div className="form-group">
                    <label htmlFor="registrationFee">Registration Fee</label>
                    <input
                        type="number"
                        id="registrationFee"
                        name="registrationFee"
                        value={registrationFee}
                        onChange={onChange}
                    />
                </div>
                <div className="form-group">
                    <label htmlFor="eventTags">Event Tags (comma-separated)</label>
                    <input
                        type="text"
                        id="eventTags"
                        name="eventTags"
                        value={eventTags}
                        onChange={onChange}
                    />
                </div>

                <FormBuilder onFormChange={handleCustomFormChange} /> {/* Render FormBuilder */}

                <button type="submit" disabled={loading}>
                    {loading ? 'Creating...' : 'Create Event'}
                </button>
            </form>
        </div>
    );
};

export default CreateEvent;

